import{_ as a,c as t,o,aj as n}from"./chunks/framework.SxNn8fcm.js";const u=JSON.parse('{"title":"How It Works","description":"","frontmatter":{},"headers":[],"relativePath":"guide/how-it-works.md","filePath":"guide/how-it-works.md","lastUpdated":1782821724000}'),i={name:"guide/how-it-works.md"};function s(r,e,c,l,d,h){return o(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h1><p>Scanic turns a casual photo of a document into a clean, flat scan in two phases: <strong>detection</strong> (find the four corners) and <strong>extraction</strong> (warp the quad into a rectangle). Here&#39;s the journey of a single image, kept conceptual — you don&#39;t need to understand any of it to use the library.</p><h2 id="the-pipeline" tabindex="-1">The pipeline <a class="header-anchor" href="#the-pipeline" aria-label="Permalink to &quot;The pipeline&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Image ─▶ Downscale + grayscale ─▶ Blur ─▶ Canny edges ─▶ Dilate</span></span>
<span class="line"><span>      ─▶ Find contours ─▶ Pick best quad ─▶ Order corners ─▶ Warp ─▶ Scan</span></span>
<span class="line"><span>         └────────────── detection ──────────────┘   └─ extraction ─┘</span></span></code></pre></div><h3 id="_1-prepare-downscale-grayscale" tabindex="-1">1. Prepare: downscale &amp; grayscale <a class="header-anchor" href="#_1-prepare-downscale-grayscale" aria-label="Permalink to &quot;1. Prepare: downscale &amp; grayscale&quot;">​</a></h3><p>The source image is drawn to a canvas and scaled down so its longest side is at most <a href="/scanic/api/reference#options"><code>maxProcessingDimension</code></a> (800px by default). Working on a smaller image makes detection dramatically faster, and the detected corners are scaled back up to full resolution at the end. In the same pass the pixels are converted to grayscale (BT.709 luminance), since edges don&#39;t need colour.</p><h3 id="_2-blur-wasm" tabindex="-1">2. Blur (WASM) <a class="header-anchor" href="#_2-blur-wasm" aria-label="Permalink to &quot;2. Blur (WASM)&quot;">​</a></h3><p>A Gaussian blur smooths out noise and texture so that only meaningful edges survive. This is one of the hot loops handled by the <strong>Rust/WebAssembly</strong> core with SIMD optimizations.</p><h3 id="_3-edge-detection-wasm" tabindex="-1">3. Edge detection (WASM) <a class="header-anchor" href="#_3-edge-detection-wasm" aria-label="Permalink to &quot;3. Edge detection (WASM)&quot;">​</a></h3><p>A <strong>Canny edge detector</strong> finds the document&#39;s outline. It uses Sobel gradients, non-maximum suppression to thin edges to one pixel wide, and hysteresis thresholding to keep only connected, confident edges. Thresholds are <strong>adaptive</strong> by default, but you can pin them with <a href="/scanic/api/reference#options"><code>lowThreshold</code></a> / <code>highThreshold</code>.</p><h3 id="_4-dilation-wasm" tabindex="-1">4. Dilation (WASM) <a class="header-anchor" href="#_4-dilation-wasm" aria-label="Permalink to &quot;4. Dilation (WASM)&quot;">​</a></h3><p>Real photos produce broken edges. A morphological <strong>dilation</strong> thickens and reconnects edge fragments so the document border becomes a continuous loop. Tunable via <a href="/scanic/api/reference#options"><code>dilationKernelSize</code></a> and <code>dilationIterations</code>.</p><h3 id="_5-contour-detection-corner-selection" tabindex="-1">5. Contour detection &amp; corner selection <a class="header-anchor" href="#_5-contour-detection-corner-selection" aria-label="Permalink to &quot;5. Contour detection &amp; corner selection&quot;">​</a></h3><p>Scanic traces the closed contours in the edge map and scores the largest candidates to find the one that best looks like a document — checking area coverage, fill ratio, aspect ratio, and how close its corners are to right angles. The winning contour is approximated to a four-point polygon, and its points are ordered into <code>topLeft</code>, <code>topRight</code>, <code>bottomRight</code>, <code>bottomLeft</code>.</p><div class="tip custom-block"><p class="custom-block-title">Adaptive cascade</p><p>If the first pass isn&#39;t confident enough (<a href="/scanic/api/reference#options"><code>minCascadeTriggerConfidence</code></a>), Scanic automatically retries with alternative profiles (different thresholds/dilation) to handle hard, low-contrast images. This is the <code>enableDetectionCascade</code> behaviour.</p></div><h3 id="_6-extraction-the-perspective-warp" tabindex="-1">6. Extraction: the perspective warp <a class="header-anchor" href="#_6-extraction-the-perspective-warp" aria-label="Permalink to &quot;6. Extraction: the perspective warp&quot;">​</a></h3><p>In <code>extract</code> mode, the four corners define a quadrilateral that gets mapped onto a clean rectangle. Instead of a slow per-pixel loop, Scanic uses a <strong>triangle subdivision</strong> technique that hands the heavy lifting to the GPU via the Canvas API — completing the warp in roughly <strong>10ms</strong>.</p><h2 id="why-hybrid-js-wasm" tabindex="-1">Why hybrid JS + WASM? <a class="header-anchor" href="#why-hybrid-js-wasm" aria-label="Permalink to &quot;Why hybrid JS + WASM?&quot;">​</a></h2><ul><li><strong>JavaScript layer</strong> — the high-level API, DOM/canvas handling, contour logic, and workflow coordination.</li><li><strong>WebAssembly layer</strong> — the pixel-crunching inner loops: Gaussian blur, Sobel gradients, non-maximum suppression, hysteresis, and dilation.</li></ul><p>This split keeps the bundle tiny (~100KB) while delivering near-native speed where it matters.</p><div class="info custom-block"><p class="custom-block-title">Graceful fallback</p><p>If the engine can&#39;t run the WASM module (for example, very old Chromium in some Electron builds), Scanic transparently falls back to a pure-JavaScript implementation. See the <a href="/scanic/guide/electron">Electron guide</a>.</p></div>`,21)])])}const g=a(i,[["render",s]]);export{u as __pageData,g as default};
